        if p == "ceremonialCounty":
            return f"{s} is in the ceremonial county of {o}"
        if p == "countySeat":
            return f"The county seat of {s} is {o}"
        if p == "chief":
            return f"The chief of {s} is {o}"
        if p == "leader":
            return f"{s} is led by {o}"
        if p == "leaderParty":
            return f"{s}'s leader party is {o}"
        if p == "leaderTitle":
            return f"{s}'s leader title is {o}"
        if p == "mayor":
            return f"{s}'s mayor is {o}"
        if p == "nativeName":
            return f"{s}'s native name is {o}"
        if p == "administrativeArrondissement":
            return f"{s} is in the administrative arrondissement of {o}"
        if p == "demonym":
            return f"The demonym of {s} is {o}"
        if p == "jurisdiction":
            return f"{s} has jurisdiction over {o}"
