        if p == "transportAircraft":
            return f"{s} uses {o} as transport aircraft"
        if p == "aircraftHelicopter":
            return f"{s} uses {o} as helicopter"
        if p == "aircraftFighter":
            return f"{s} uses {o} as fighter aircraft"
        if p == "attackAircraft":
            return f"{s} uses {o} as attack aircraft"
        if p == "battle":
            return f"{s} participated in the {o}"
        if p == "1stRunwayLengthFeet":
            return f"{s}'s first runway is {o} feet long"
        if p == "4thRunwayLengthFeet":
            return f"{s}'s fourth runway is {o} feet long"
        # Fallback
        return f"{s} has {p} {o}"

    # Build subject‑level clauses, merging multiple predicates per subject
    subject_clauses: list[str] = []
    for s, pairs in subj_map.items():
        parts = [_phrase(s, p, o) for p, o in pairs]
        if len(parts) == 1:
            subject_clauses.append(parts[0])
        else:
            merged = ", ".join(parts[:-1]) + ", and " + parts[-1]
            subject_clauses.append(merged)

    # Combine all subject clauses into one sentence with better relative clause structure
    if len(subject_clauses) == 1:
        sentence = subject_clauses[0] + "."
    elif len(subject_clauses) == 2:
        # Try to use relative clauses for better flow
        first = subject_clauses[0]
        second = subject_clauses[1]
        # Check if we can connect with "which is" or "where"
        if "is in" in second or "is located" in second or "is part of" in second:
            sentence = first + " which is in " + second.split("is in ")[1] + "."
        else:
            sentence = first + ", and " + second + "."
    else:
        # For multiple subjects, use relative clauses where possible
        first = subject_clauses[0]
        rest = subject_clauses[1:]
        parts = []
        for i, clause in enumerate(rest):
            if i == 0:
                if "is in" in clause or "is located" in clause or "is part of" in clause:
                    parts.append("which is in " + clause.split("is in ")[1] if "is in" in clause else
                                 "which is located in " + clause.split("is located in ")[1] if "is located" in clause else
                                 "which is part of " + clause.split("is part of ")[1])
                else:
                    parts.append("and " + clause)
            else:
                if "is in" in clause or "is located" in clause or "is part of" in clause:
                    parts.append(", where " + clause.split("is in ")[1] if "is in" in clause else
                                 ", where it is located in " + clause.split("is located in ")[1] if "is located" in clause else
                                 ", where it is part of " + clause.split("is part of ")[1])
                else:
                    parts.append(", and " + clause)
        sentence = first + ", " + ", ".join(parts) + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

